import{_ as r,o as e,c as p,ag as h}from"./chunks/framework.BZohXCq9.js";const c=JSON.parse('{"title":"Day1 - 我是阿野，这是我的野径","description":"阿野的个人博客开篇，讲述双非本科、在职读研的逆袭故事。记录 Python 学习、英语提升、个人成长的真实经历。","frontmatter":{"title":"Day1 - 我是阿野，这是我的野径","description":"阿野的个人博客开篇，讲述双非本科、在职读研的逆袭故事。记录 Python 学习、英语提升、个人成长的真实经历。","keywords":"阿野，个人博客，双非本，在职读研，逆袭，Python 学习，英语提升，自律","date":"2026-03-15T00:00:00.000Z","tags":["个人成长，双非本，私企，逆袭"]},"headers":[],"relativePath":"blog/day1-wild-path.md","filePath":"blog/day1-wild-path.md","lastUpdated":1773645500000}'),t={name:"blog/day1-wild-path.md"};function l(i,a,d,n,o,b){return e(),p("div",null,[...a[0]||(a[0]=[h('<h1 id="👋-这里是阿野的野径-day1" tabindex="-1"><a class="header-anchor" href="#👋-这里是阿野的野径-day1">¶</a> 👋 这里是阿野的野径，Day1</h1><h2 id="📌-我是阿野" tabindex="-1"><a class="header-anchor" href="#📌-我是阿野">¶</a> 📌 我是阿野</h2><p>98 年，双非本，理科男<br> 在私企当了 5 年螺丝钉</p><p>每天重复着同样的工作<br> 拿着不温不火的工资<br> 看着身边的同事<br> 有的跳槽涨薪<br> 有的考公上岸<br> 有的创业成功</p><p>而我，还在原地踏步</p><h2 id="💡-为什么要走野径" tabindex="-1"><a class="header-anchor" href="#💡-为什么要走野径">¶</a> 💡 为什么要走野径</h2><p>双非本的学历<br> 让我在求职时被卡<br> 在升职时被忽略<br> 在相亲时被嫌弃</p><p>私企的工作<br> 让我没有时间学习<br> 没有精力提升<br> 没有底气跳槽</p><p>直到上个月</p><p>公司裁员，我上了名单<br> HR 说：「你的岗位，随时可以找到人替代」</p><p>那一刻我明白了</p><p>继续走大路，我永远是配角<br> 不如走野径，做自己的主角</p><h2 id="📚-我的野径计划" tabindex="-1"><a class="header-anchor" href="#📚-我的野径计划">¶</a> 📚 我的野径计划</h2><p>✅ 学 Python - 提升竞争力<br> 目标：3 个月入门，能写小工具</p><p>✅ 学英语 - 开阔视野<br> 目标：6 个月，能流利交流</p><p>✅ 在职读研 - 提升学历<br> 目标：1 年，上岸 985/211</p><p>✅ 用 OpenClaw - 提高效率<br> 目标：自动化日常工作</p><p>✅ 定期旅行 - 放松身心<br> 目标：每月一次短途旅行</p><h2 id="🎯-这个账号会分享" tabindex="-1"><a class="header-anchor" href="#🎯-这个账号会分享">¶</a> 🎯 这个账号会分享</h2><ul><li>Python 学习记录 (从 0 到 1)</li><li>英语学习心得 (英语渣的自救)</li><li>在职读研经验 (双非本的逆袭)</li><li>OpenClaw 工具使用 (打工人效率提升)</li><li>旅行生活 (工作再忙也要看世界)</li><li>个人成长感悟 (普通人的自救)</li></ul><h2 id="💪-给自己的目标" tabindex="-1"><a class="header-anchor" href="#💪-给自己的目标">¶</a> 💪 给自己的目标</h2><ul><li>3 个月：Python 入门，效率提升 50%</li><li>6 个月：英语能交流，敢开口</li><li>1 年：在职研究生上岸</li><li>持续：用 OpenClaw 提升效率</li></ul><h2 id="🤝-给同行者" tabindex="-1"><a class="header-anchor" href="#🤝-给同行者">¶</a> 🤝 给同行者</h2><p>如果你也和我一样<br> 是个双非本、在私企打拼的普通人<br> 那欢迎关注我</p><p>我们一起学习<br> 一起成长<br> 一起探路</p><p>野径不通，那就踩出一条路</p><h2 id="💬-互动时间" tabindex="-1"><a class="header-anchor" href="#💬-互动时间">¶</a> 💬 互动时间</h2><p>你是哪年的？<br> 现在在做什么？<br> 有什么想要改变的？</p><p>评论区告诉我<br> 每条都会回复</p><hr><p>📍 阿野的野径 Day1<br> 🎯 同行者，评论区见<br> 「野径不通，那就踩出一条路」</p><p><a href="https://www.xiaohongshu.com/explore/69b69fa0000000001a0258cd" target="_blank" rel="noreferrer">→ 返回小红书查看原文</a></p>',32)])])}const _=r(t,[["render",l]]);export{c as __pageData,_ as default};
